PyLearn.createEditor({ containerId: 'editor-strings', initialCode: 'print("Hello, World!")
print(\'Python is fun\')
print("I\'m learning Python")', label: 'Strings' });

PyLearn.createEditor({ containerId: 'editor-multi', initialCode: 'print("My name is", "Alice")
print("I am", 25, "years old")
print("Pi is approximately", 3.14159)', label: 'Multiple values' });

(function(){
  PyLearn.createEditor({
    containerId: 'editor-ch1',
    initialCode: '# Write your print() statement below\n',
    label: 'Challenge 1',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c There is an error in your code: ' + error };
      var trimmed = output.replace(/\n$/,'');
      if (trimmed === 'Hello, Python!') {
        return { pass: true, message: '\u2705 Perfect! Your output matches exactly.' };
      }
      if (!output.trim()) return { pass: false, message: '\u26a0\ufe0f Nothing was printed yet. Try writing a print() statement.' };
      return { pass: false, message: '\u274c Output was: "' + trimmed + '" — check spelling, punctuation and capitalisation.' };
    },
    onPass: async function() {
      await window.__markStepComplete();
    }
  });
})();

(function(){
  PyLearn.createEditor({
    containerId: 'editor-ch2',
    initialCode: '# Print the result of 17 * 6\n',
    label: 'Challenge 2',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Error: ' + error };
      if (output.trim() === '102') {
        if (/102/.test(code) && !/\*/.test(code)) {
          return { pass: false, message: '\u26a0\ufe0f Close! But use Python to calculate it rather than typing the answer.' };
        }
        return { pass: true, message: '\u2705 Correct! 17 \u00d7 6 = 102.' };
      }
      if (!output.trim()) return { pass: false, message: '\u26a0\ufe0f Nothing printed yet.' };
      return { pass: false, message: '\u274c Got ' + output.trim() + ' \u2014 expected 102. Remember: 17 * 6.' };
    },
    onPass: async function() {
      await window.__markStepComplete();
    }
  });
})();

(function(){
  PyLearn.createEditor({
    containerId: 'editor-ch3',
    initialCode: 'language = "Python"\nage = 34\n# Write your f-string print() below\n',
    label: 'Challenge 3',
    validate: async function(output, error, code) {
      if (error) return { pass: false, message: '\u274c Error: ' + error };
      var expected = 'My favourite language is Python and it is 34 years old.';
      var trimmed  = output.replace(/\n$/,'');
      if (trimmed !== expected) {
        if (!output.trim()) return { pass: false, message: '\u26a0\ufe0f Nothing printed yet.' };
        return { pass: false, message: '\u274c Output was: "' + trimmed + '" \u2014 check it matches the target exactly.' };
      }
      if (!/f["\']/.test(code)) {
        return { pass: false, message: '\u26a0\ufe0f Output is correct, but please use an f-string (start your string with f"...).' };
      }
      return { pass: true, message: '\u2705 Excellent! That is a perfect f-string.' };
    },
    onPass: async function() {
      await window.__markStepComplete();
    }
  });
})();

(function(){
  var questions = [
    { q: 'Which of the following correctly prints: Hello, World!', options: ['print(Hello, World!)', 'print("Hello, World!")', 'PRINT("Hello, World!")', 'echo "Hello, World!"'], answer: 1 },
    { q: 'What does print(3 + 4) output?', options: ['3 + 4', '"3 + 4"', '7', 'Error'], answer: 2 },
    { q: 'Which argument changes the separator between printed items?', options: ['end', 'sep', 'join', 'split'], answer: 1 },
    { q: 'What is the output of: print(f"I have {2 + 3} apples")', options: ['I have {2 + 3} apples', 'I have 5 apples', 'Error', 'I have 2 + 3 apples'], answer: 1 }
  ];
  var container = document.getElementById('quiz-container');
  var selected = {};
  questions.forEach(function(q, qi) {
    var block = document.createElement('div');
    block.className = 'q-block';
    block.innerHTML = '<p>' + (qi+1) + '. ' + q.q + '</p>';
    q.options.forEach(function(opt, oi) {
      var btn = document.createElement('button');
      btn.className = 'option';
      btn.textContent = opt;
      btn.onclick = function() {
        block.querySelectorAll('.option').forEach(function(b){ b.style.outline=''; });
        btn.style.outline = '2px solid #2563eb';
        selected[qi] = oi;
      };
      block.appendChild(btn);
    });
    container.appendChild(block);
  });
  var submitBtn = document.createElement('button');
  submitBtn.id = 'quiz-submit';
  submitBtn.textContent = 'Submit Answers';
  submitBtn.onclick = async function() {
    var score = 0;
    questions.forEach(function(q, qi) {
      var block = container.children[qi];
      var opts = block.querySelectorAll('.option');
      opts.forEach(function(btn, oi) {
        if (oi === q.answer) btn.classList.add('correct');
        else if (oi === selected[qi]) btn.classList.add('wrong');
        btn.disabled = true;
      });
      if (selected[qi] === q.answer) score++;
    });
    submitBtn.disabled = true;
    var result = document.getElementById('quiz-result');
    result.classList.remove('hidden');
    if (score === questions.length) {
      result.className = 'mt-4 p-4 rounded-lg bg-green-50 border border-green-200 text-green-800';
      result.innerHTML = '<strong>\u2705 Perfect score! ' + score + '/' + questions.length + '</strong> \u2014 You have mastered the print() function!';
      await window.__markStepComplete();
    } else {
      result.className = 'mt-4 p-4 rounded-lg bg-yellow-50 border border-yellow-200 text-yellow-800';
      result.innerHTML = '<strong>Score: ' + score + '/' + questions.length + '</strong> \u2014 Review the highlighted answers and try again.';
    }
  };
  container.appendChild(submitBtn);
})();
